UPDATE comment
content = #{content}, status = #{status}, reject_reason = #{rejectReason},
WHERE id = #{id}

mapper.select:
SELECT c.*, u.nickname as user_name, u.avatar as user_avatar, u.nickname as user_nickname, u.username as user_username, ru.nickname as reply_to_user_name, a.title as article_title FROM comment c LEFT JOIN user u ON c.user_id = u.id LEFT JOIN user ru ON c.reply_to_user_id = ru.id LEFT JOIN article a ON c.article_id = a.id
AND (c.content LIKE CONCAT('%', #{keyword}, '%') OR a.title LIKE CONCAT('%', #{keyword}, '%'))
AND c.status = #{status}
ORDER BY c.created_at DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM comment c LEFT JOIN article a ON c.article_id = a.id
AND (c.content LIKE CONCAT('%', #{keyword}, '%') OR a.title LIKE CONCAT('%', #{keyword}, '%'))
AND c.status = #{status}
